import{_ as a,o as r,c as e,a2 as o}from"./chunks/framework.Cr-Z7ngm.js";const u=JSON.parse('{"title":"期权买方","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"derivatives/options-buyer.md","filePath":"zh-CN/derivatives/options-buyer.md"}'),l={name:"derivatives/options-buyer.md"};function d(i,t,n,h,s,p){return r(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="期权买方" tabindex="-1">期权买方 <a class="header-anchor" href="#期权买方" aria-label="Permalink to &quot;期权买方&quot;">​</a></h1><p>期权买方权利特征、买入看涨和看跌期权的盈亏计算及行权选择。</p><h2 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h2><p>期权买方即权利方，通过支付权利金获得在未来特定时间以特定价格买入或卖出资产的选择权。核心特征：只享有权利，不承担义务。</p><p>在持仓页面体现为期权多头仓位（期权持仓数量为正数）。</p><h3 id="风险与收益" tabindex="-1">风险与收益 <a class="header-anchor" href="#风险与收益" aria-label="Permalink to &quot;风险与收益&quot;">​</a></h3><ul><li>最大亏损：仅限于购买期权时支付的权利金，无论市场如何波动</li><li>潜在收益：理论上无限（看涨期权）或极大（看跌期权，股价最低为 0）</li></ul><hr><h2 id="买入看涨期权-long-call" tabindex="-1">买入看涨期权（Long Call） <a class="header-anchor" href="#买入看涨期权-long-call" aria-label="Permalink to &quot;买入看涨期权（Long Call）&quot;">​</a></h2><p>具有到期以约定价格买入正股的权利。当标的资产市价高于行权价时，行使权利有利可图。</p><h3 id="盈亏计算" tabindex="-1">盈亏计算 <a class="header-anchor" href="#盈亏计算" aria-label="Permalink to &quot;盈亏计算&quot;">​</a></h3><table tabindex="0"><thead><tr><th>到期操作</th><th>盈亏</th></tr></thead><tbody><tr><td>行权</td><td>盈利 =（股票市价 - 行权价 - 权利金）× 股票数</td></tr><tr><td>放弃行权</td><td>损失 = 支付的权利金（最大损失）</td></tr></tbody></table><h3 id="示例" tabindex="-1">示例 <a class="header-anchor" href="#示例" aria-label="Permalink to &quot;示例&quot;">​</a></h3><p>以权利金 5 USD 买入 1 张看涨期权，行权价 50，合约 100 股，支出 500 USD：</p><p><strong>股价 40（市价 &lt; 行权价）</strong><br> 行权盈亏 =（40 - 50 - 5）× 100 = -1,500 USD，放弃行权仅损失权利金 500 USD → 选择不行权</p><p><strong>股价 50（市价 = 行权价）</strong><br> 行权盈亏 =（50 - 50 - 5）× 100 = -500 USD，与权利金相等 → 选择不行权</p><p><strong>股价 60（市价 &gt; 行权价）</strong><br> 行权盈亏 =（60 - 50 - 5）× 100 = 500 USD → 可选择卖出期权或行权获得股票</p><hr><h2 id="买入看跌期权-long-put" tabindex="-1">买入看跌期权（Long Put） <a class="header-anchor" href="#买入看跌期权-long-put" aria-label="Permalink to &quot;买入看跌期权（Long Put）&quot;">​</a></h2><p>具有到期以约定价格卖出正股的权利。当标的资产市价低于行权价时，行使权利有利可图。</p><h3 id="盈亏计算-1" tabindex="-1">盈亏计算 <a class="header-anchor" href="#盈亏计算-1" aria-label="Permalink to &quot;盈亏计算&quot;">​</a></h3><table tabindex="0"><thead><tr><th>到期操作</th><th>盈亏</th></tr></thead><tbody><tr><td>行权</td><td>盈利 =（行权价 - 股票市价 - 权利金）× 股票数</td></tr><tr><td>放弃行权</td><td>损失 = 支付的权利金（最大损失）</td></tr></tbody></table><h3 id="示例-1" tabindex="-1">示例 <a class="header-anchor" href="#示例-1" aria-label="Permalink to &quot;示例&quot;">​</a></h3><p>以权利金 5 USD 买入 1 张看跌期权，行权价 50，合约 100 股，支出 500 USD：</p><p><strong>股价 40（市价 &lt; 行权价）</strong><br> 行权盈亏 =（50 - 40 - 5）× 100 = 500 USD → 盈利，可选择卖出期权或行权卖出股票</p><p><strong>股价 50（市价 = 行权价）</strong><br> 行权盈亏 =（50 - 50 - 5）× 100 = -500 USD，与权利金相等 → 选择不行权</p><p><strong>股价 60（市价 &gt; 行权价）</strong><br> 行权盈亏 =（50 - 60 - 5）× 100 = -1,500 USD，放弃行权仅损失 500 USD → 选择不行权</p><hr><h2 id="行权选择" tabindex="-1">行权选择 <a class="header-anchor" href="#行权选择" aria-label="Permalink to &quot;行权选择&quot;">​</a></h2><p>期权到期时：</p><ul><li>市场价格有利：可选择行使权利</li><li>市场价格不利：可选择放弃权利，最大损失为已支付的权利金</li></ul><p>注意：长桥目前不支持主动提前行权，到期时价内期权自动行权，价外期权自动作废。</p>',32)])])}const c=a(l,[["render",d]]);export{u as __pageData,c as default};
